module mux_4to1_8bit (selected_data, in0, in1, in2, in3, sel);
   input [7:0] in0, in1, in2, in3;
   input [1:0] sel;
   output [7:0] selected_data;

   reg [7:0] selected_data;

always @(*) begin
    case (sel)
        2'b00: selected_data = in0;
        2'b01: selected_data = in1;
        2'b10: selected_data = in2;
        2'b11: selected_data = in3;
        default: selected_data = 8'b0;
    endcase
end

endmodule
